import React, { useEffect, useState } from "react";
import FAWInput from "../../../../component-widget/FAWInput";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWButton from "../../../../component-widget/FAWButton";
import FAWItemOptionsEditor from "./shared/FAWItemOptionsEditor";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";
import FAWFlagSettings from "./shared/FAWFlagSettings";
import FAWAddPrefill from "./shared/FAWAddPrefill";
import FAWCloningOptions from "./shared/FAWCloningOptions";

export default function QueDataGridEntryItemEditor({ 
  data, 
  onSave, 
  onClose, 
  saveRef, 
  isDefaultLanguage = true,
  availableDroplists = [],
  availableFormFields = [],
  availableRefDomains = [],
  domains = []
}) {
  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      columns: [],
      flagSettings: {},
      prefillSettings: {},
      cloningOptions: {},
    }
  );
  // Add isSubForm state
  const [isSubForm, setIsSubForm] = useState(data?.isSubForm || false);

  const [editingColumn, setEditingColumn] = useState(null);
  const [newColumn, setNewColumn] = useState({
    name: "",
    heading: "",
    width: "",
    type: "Textbox",
    required: false,
    options: [],
    optionsRefDomain: "",
    prefillDependency: "",
  });

  useEffect(() => { 
    if (data) setItem(prev => ({ ...prev, ...data })); 
  }, [data]);

  const handleChange = (field, value) => setItem(prev => ({ ...prev, [field]: value }));
  const handleSave = () => { 
    onSave?.(item); 

  };

  const handleAddColumn = () => {
    if (!newColumn.name || !newColumn.heading) {
      alert("Column Name and Heading are required");
      return;
    }

    // Check for duplicate column names
    const existingColumn = item.columns.find(col => 
      col.name.toLowerCase() === newColumn.name.toLowerCase()
    );
    
    if (existingColumn) {
      alert(`A column with the name "${newColumn.name}" already exists. Please choose a different name.`);
      return;
    }

    const column = {
      id: Date.now(),
      ...newColumn,
      index: item.columns.length
    };

    setItem(prev => ({
      ...prev,
      columns: [...prev.columns, column]
    }));

    // Reset form
    setNewColumn({
      name: "",
      heading: "",
      width: "",
      type: "Textbox",
      required: false,
      options: [],
      optionsRefDomain: "",
      prefillDependency: "",
    });
  };

  const handleEditColumn = (column) => {
    setEditingColumn(column);
    setNewColumn({
      name: column.name,
      heading: column.heading,
      width: column.width,
      type: column.type,
      required: column.required,
      options: column.options || [],
      optionsRefDomain: column.optionsRefDomain || "",
      prefillDependency: column.prefillDependency || "",
    });
  };

  const handleUpdateColumn = () => {
    if (!editingColumn) return;

    if (!newColumn.name || !newColumn.heading) {
      alert("Column Name and Heading are required");
      return;
    }

    // Check for duplicate column names (excluding current column)
    const existingColumn = item.columns.find(col => 
      col.id !== editingColumn.id && 
      col.name.toLowerCase() === newColumn.name.toLowerCase()
    );
    
    if (existingColumn) {
      alert(`A column with the name "${newColumn.name}" already exists. Please choose a different name.`);
      return;
    }

    const updatedColumns = item.columns.map(col => 
      col.id === editingColumn.id 
        ? { ...col, ...newColumn }
        : col
    );

    setItem(prev => ({
      ...prev,
      columns: updatedColumns
    }));

    // Reset editing state
    setEditingColumn(null);
    setNewColumn({
      name: "",
      heading: "",
      width: "",
      type: "Textbox",
      required: false,
      options: [],
      optionsRefDomain: "",
      prefillDependency: "",
    });
  };

  const handleDeleteColumn = (columnId) => {
    if (confirm("Are you sure you want to delete this column?")) {
      setItem(prev => ({
        ...prev,
        columns: prev.columns.filter(col => col.id !== columnId)
      }));
    }
  };

  const handleMoveColumn = (columnId, direction) => {
    const columns = [...item.columns];
    const index = columns.findIndex(col => col.id === columnId);
    
    if (direction === 'up' && index > 0) {
      [columns[index], columns[index - 1]] = [columns[index - 1], columns[index]];
    } else if (direction === 'down' && index < columns.length - 1) {
      [columns[index], columns[index + 1]] = [columns[index + 1], columns[index]];
    }

    setItem(prev => ({ ...prev, columns }));
  };

  const getColumnTypeOptions = () => [
    { label: "Drop Down List", value: "DropDownList" },
    { label: "Text Box", value: "Textbox" },
    { label: "Date", value: "Date" },
    { label: "Relationship Selector", value: "RelationshipSelector" }
  ];

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={setItem} isDefaultLanguage={isDefaultLanguage} questionType="DataGridEntryItemType" />
      
      <EditorSection title="DataGrid Options">
        <div style={{ marginBottom: 16 }}>
          <FAWInput 
            label="Name" 
            value={item.name} 
            onChange={(e) => handleChange("name", e.target.value)} 
            fullWidth 
          />
          <FAWInput 
            label="Description" 
            value={item.text} 
            onChange={(e) => handleChange("text", e.target.value)} 
            multiline 
            rows={3}
            fullWidth 
          />
        </div>
      </EditorSection>

      <EditorSection title="Add Column">
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
          <FAWInput 
            label="Name (Save Value)" 
            value={newColumn.name} 
            onChange={(e) => setNewColumn(prev => ({ ...prev, name: e.target.value }))} 
            fullWidth 
          />
          <FAWInput 
            label="Column Heading (Display Name)" 
            value={newColumn.heading} 
            onChange={(e) => setNewColumn(prev => ({ ...prev, heading: e.target.value }))} 
            fullWidth 
          />
        </div>
        
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 16, marginBottom: 16 }}>
          <FAWInput 
            label="Column Width (px)" 
            value={newColumn.width} 
            onChange={(e) => setNewColumn(prev => ({ ...prev, width: e.target.value }))} 
            type="number"
            fullWidth 
          />
          <FAWDropdown 
            label="Question Type" 
            value={newColumn.type} 
            options={getColumnTypeOptions()}
            onChange={(opt) => setNewColumn(prev => ({ ...prev, type: opt.value }))} 
            fullWidth 
          />
          <div style={{ display: "flex", alignItems: "center", marginTop: 24 }}>
            <FAWCheckbox 
              label="Required" 
              checked={newColumn.required} 
              onChange={(e) => setNewColumn(prev => ({ ...prev, required: e.target.checked }))} 
            />
          </div>
        </div>

        {newColumn.type === "DropDownList" && (
          <div style={{ marginTop: 16, padding: 16, border: "1px solid #e0e0e0", borderRadius: 4 }}>
            <h4 style={{ margin: "0 0 16px 0" }}>Drop Down Options</h4>
            <FAWItemOptionsEditor
              options={newColumn.options}
              optionsRefDomain={newColumn.optionsRefDomain}
              allowConflictFlag={false}
              allowedModes={["RefCode", "StaticList", "Dependency", "FormField"]}
              availableDroplists={availableDroplists}
              availableFormFields={availableFormFields}
              availableRefDomains={availableRefDomains}
              domains={domains}
              isCustomField={item._source?.rc?.Domain === "CustomFields"}
              onChange={(payload) => {
                setNewColumn(prev => ({
                  ...prev,
                  options: payload.options || [],
                  optionsRefDomain: payload.optionsRefDomain || "",
                  optionsPayload: payload
                }));
              }}
            />
          </div>
        )}



        <div style={{ display: "flex", gap: 8, marginTop: 16 }}>
          {editingColumn ? (
            <>
              <FAWButton variant="outlined" onClick={() => setEditingColumn(null)}>
                Cancel
              </FAWButton>
              <FAWButton variant="contained" onClick={handleUpdateColumn}>
                Update Column
              </FAWButton>
            </>
          ) : (
            <FAWButton variant="contained" onClick={handleAddColumn}>
              Add Column
            </FAWButton>
          )}
        </div>
      </EditorSection>

      {item.columns.length > 0 && (
        <EditorSection title="Saved Columns">
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr style={{ backgroundColor: "#f5f5f5" }}>
                  <th style={{ padding: "8px", textAlign: "left", border: "1px solid #ddd" }}>Name</th>
                  <th style={{ padding: "8px", textAlign: "left", border: "1px solid #ddd" }}>Display Text</th>
                  <th style={{ padding: "8px", textAlign: "left", border: "1px solid #ddd" }}>Column Type</th>
                  <th style={{ padding: "8px", textAlign: "left", border: "1px solid #ddd" }}>Width (px)</th>
                  <th style={{ padding: "8px", textAlign: "left", border: "1px solid #ddd" }}>Required</th>
                  <th style={{ padding: "8px", textAlign: "left", border: "1px solid #ddd" }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {item.columns.map((column, index) => (
                  <tr key={column.id} style={{ backgroundColor: index % 2 === 0 ? "#fff" : "#f9f9f9" }}>
                    <td style={{ padding: "8px", border: "1px solid #ddd" }}>{column.name}</td>
                    <td style={{ padding: "8px", border: "1px solid #ddd" }}>{column.heading}</td>
                    <td style={{ padding: "8px", border: "1px solid #ddd" }}>{column.type}</td>
                    <td style={{ padding: "8px", border: "1px solid #ddd" }}>{column.width}</td>
                    <td style={{ padding: "8px", border: "1px solid #ddd" }}>{column.required ? "Yes" : "No"}</td>
                    <td style={{ padding: "8px", border: "1px solid #ddd" }}>
                      <div style={{ display: "flex", gap: 4 }}>
                        <FAWButton 
                          size="small" 
                          variant="outlined" 
                          onClick={() => handleEditColumn(column)}
                          style={{ minWidth: "auto", padding: "4px 8px" }}
                        >
                          Edit
                        </FAWButton>
                        <FAWButton 
                          size="small" 
                          variant="outlined" 
                          onClick={() => handleDeleteColumn(column.id)}
                          style={{ minWidth: "auto", padding: "4px 8px" }}
                        >
                          Delete
                        </FAWButton>
                        <FAWButton 
                          size="small" 
                          variant="outlined" 
                          onClick={() => handleMoveColumn(column.id, 'up')}
                          disabled={index === 0}
                          style={{ minWidth: "auto", padding: "4px 8px" }}
                        >
                          ↑
                        </FAWButton>
                        <FAWButton 
                          size="small" 
                          variant="outlined" 
                          onClick={() => handleMoveColumn(column.id, 'down')}
                          disabled={index === item.columns.length - 1}
                          style={{ minWidth: "auto", padding: "4px 8px" }}
                        >
                          ↓
                        </FAWButton>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </EditorSection>
      )}

      {item.columns.length > 0 && (
        <EditorSection title="Preview Data Grid">
          <div style={{ border: "1px solid #ddd", borderRadius: 4, overflow: "hidden" }}>
            <table style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr style={{ backgroundColor: "#2196F3", color: "white" }}>
                  {item.columns.map((column) => (
                    <th key={column.id} style={{ padding: "12px 8px", textAlign: "left", border: "1px solid #ddd" }}>
                      {column.heading}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                <tr>
                  {item.columns.map((column) => (
                    <td key={column.id} style={{ padding: "12px 8px", border: "1px solid #ddd", backgroundColor: "#f9f9f9" }}>
                      {column.type === "DropDownList" && "Dropdown"}
                      {column.type === "Textbox" && "Text input"}
                      {column.type === "Date" && "Date picker"}
                      {column.type === "RelationshipSelector" && "Relationship selector"}
                    </td>
                  ))}
                </tr>
              </tbody>
            </table>
          </div>
        </EditorSection>
      )}

      <div style={{ display: 'none' }}>
        <FAWFlagSettings 
          data={item.flagSettings} 
          onChange={(data) => handleChange("flagSettings", data)}
          availableFlags={[]}
        />
      </div>
      
      {isDefaultLanguage && !isSubForm && availableFormFields.length > 0 && (
        <EditorSection title="Prefill Options">
          <FAWAddPrefill 
            data={item.prefillSettings} 
            onChange={(data) => handleChange("prefillSettings", data)}
            availablePrefillFields={availableFormFields}
          />
        </EditorSection>
      )}
      
      <FAWCloningOptions 
        data={item.cloningOptions} 
        onChange={(data) => handleChange("cloningOptions", data)}
      />
    </EditorShell>
  );
}



